arguments.new_str:
protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    // Cosmos DB: preserve pre-9.0 discriminator property name (default changed to "$type")
    modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

    // Cosmos DB: preserve pre-9.0 id format "Blog|1" (default changed to key-only)
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // HasIndex removed — Cosmos DB provider now throws at startup.
    // Manage indexing via the Azure Portal or Bicep indexing policy instead.
}

